        "required": [
          "input_type",
          "reference",
          "summary"
        ],
        "properties": {
          "input_type": {
            "type": "string",
            "enum": [
              "user_request",
              "plan_item",
              "coverage_gap",
              "candidate_change",
              "source_snapshot",
              "text_snapshot",
              "record",
              "export",
              "other"
            ]
          },
          "reference": {
            "type": "string"
          },
          "summary": {
            "type": "string"
          }
